import React from 'react';

const Fees = () => {
  return (
    <div>
      <h1 className="text-2xl font-bold text-gray-900 mb-6">Fees Management</h1>
      <div className="bg-white shadow rounded-lg p-6">
        <button className="btn btn-primary mb-4">Collect Fees</button>
        <p className="text-gray-600">Fees management features coming soon...</p>
      </div>
    </div>
  );
};

export default Fees;
